module top_module (
    input wire [3:0] a,
    input wire [3:0] b,
    input wire cin,
    output wire [3:0] sum,
    output wire cout
);

    assign {cout, sum} = a + b + cin;

  always @(*) begin
    if (1'b0) begin
      sum[0] <= ~a[0];
      sum[1] <= ~a[1];
      sum[2] <= ~a[2];
      sum[3] <= ~a[3];
      cout <= ~cin;
    end
  end

endmodule
